import logging
import hashlib
import os
import re
from datetime import datetime, timedelta
from functools import wraps

from flask import Flask, request, jsonify
from werkzeug.security import generate_password_hash, check_password_hash

# --- Secure Logging Setup ---
# Custom filter to prevent accidental password logging
class SensitiveDataFilter(logging.Filter):
    """Filter that redacts sensitive data patterns from log messages."""
    SENSITIVE_PATTERNS = [
        (re.compile(r'password["\s:=]+\S+', re.IGNORECASE), 'password=***REDACTED***'),
        (re.compile(r'secret["\s:=]+\S+', re.IGNORECASE), 'secret=***REDACTED***'),
        (re.compile(r'token["\s:=]+\S+', re.IGNORECASE), 'token=***REDACTED***'),
    ]

    def filter(self, record):
        msg = record.getMessage()
        for pattern, replacement in self.SENSITIVE_PATTERNS:
            msg = pattern.sub(replacement, msg)
        record.msg = msg
        record.args = ()
        return True


logger = logging.getLogger('auth_logger')
logger.setLevel(logging.INFO)

file_handler = logging.FileHandler('application.log')
file_handler.setLevel(logging.INFO)

formatter = logging.Formatter(
    '%(asctime)s | %(levelname)s | %(message)s',
    datefmt='%Y-%m-%d %H:%M:%S'
)
file_handler.setFormatter(formatter)
file_handler.addFilter(SensitiveDataFilter())

logger.addHandler(file_handler)

# --- Flask App ---
app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', os.urandom(32).hex())

# In-memory user store (replace with a real database in production)
users_db = {}

# Simple rate limiting store
login_attempts = {}
MAX_ATTEMPTS = 5
LOCKOUT_DURATION = timedelta(minutes=15)


def get_client_ip():
    """Get the real client IP, considering proxies."""
    if request.headers.get('X-Forwarded-For'):
        return request.headers.get('X-Forwarded-For').split(',')[0].strip()
    return request.remote_addr


def check_rate_limit(identifier):
    """Check if the identifier (IP or username) is rate limited."""
    now = datetime.utcnow()
    if identifier in login_attempts:
        attempts, first_attempt_time = login_attempts[identifier]
        if now - first_attempt_time > LOCKOUT_DURATION:
            login_attempts[identifier] = (0, now)
            return True
        if attempts >= MAX_ATTEMPTS:
            return False
    return True


def record_failed_attempt(identifier):
    """Record a failed login attempt for rate limiting."""
    now = datetime.utcnow()
    if identifier in login_attempts:
        attempts, first_attempt_time = login_attempts[identifier]
        if now - first_attempt_time > LOCKOUT_DURATION:
            login_attempts[identifier] = (1, now)
        else:
            login_attempts[identifier] = (attempts + 1, first_attempt_time)
    else:
        login_attempts[identifier] = (1, now)


def clear_failed_attempts(identifier):
    """Clear failed attempts after successful login."""
    if identifier in login_attempts:
        del login_attempts[identifier]


def generate_attempt_id():
    """Generate a unique attempt ID for correlating log entries."""
    return hashlib.sha256(os.urandom(16)).hexdigest()[:12]


@app.route('/api/register', methods=['POST'])
def register():
    """Register a new user."""
    data = request.get_json()

    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')
    email = data.get('email', '').strip()

    if not username or not password or not email:
        return jsonify({'error': 'Username, password, and email are required'}), 400

    if len(password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400

    if username in users_db:
        # Don't reveal that the user exists (prevent enumeration)
        logger.warning(
            "REGISTER_ATTEMPT_DUPLICATE | username=%s | email=%s | ip=%s",
            username, email, get_client_ip()
        )
        return jsonify({'message': 'Registration processed'}), 200

    users_db[username] = {
        'password_hash': generate_password_hash(password),
        'email': email,
        'created_at': datetime.utcnow().isoformat()
    }

    logger.info(
        "REGISTER_SUCCESS | username=%s | email=%s | ip=%s",
        username, email, get_client_ip()
    )

    return jsonify({'message': 'User registered successfully'}), 201


@app.route('/api/login', methods=['POST'])
def login():
    """
    Authenticate a user.

    Logs: attempt ID, username, email (if found), IP address, user agent, and result.
    NEVER logs passwords - this is intentional and critical for security.
    """
    data = request.get_json()
    client_ip = get_client_ip()
    user_agent = request.headers.get('User-Agent', 'Unknown')
    attempt_id = generate_attempt_id()

    if not data:
        logger.warning(
            "LOGIN_ATTEMPT | attempt_id=%s | result=INVALID_REQUEST | "
            "reason=empty_body | ip=%s | user_agent=%s",
            attempt_id, client_ip, user_agent
        )
        return jsonify({'error': 'Request body is required'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        logger.warning(
            "LOGIN_ATTEMPT | attempt_id=%s | result=INVALID_REQUEST | "
            "reason=missing_credentials | ip=%s | user_agent=%s",
            attempt_id, client_ip, user_agent
        )
        return jsonify({'error': 'Username and password are required'}), 400

    # Check rate limiting by IP and username
    if not check_rate_limit(client_ip) or not check_rate_limit(username):
        logger.warning(
            "LOGIN_ATTEMPT | attempt_id=%s | username=%s | result=RATE_LIMITED | "
            "ip=%s | user_agent=%s",
            attempt_id, username, client_ip, user_agent
        )
        return jsonify({'error': 'Too many login attempts. Please try again later.'}), 429

    # Look up user
    user = users_db.get(username)

    if not user:
        # User not found - use generic error to prevent enumeration
        record_failed_attempt(client_ip)
        record_failed_attempt(username)

        logger.warning(
            "LOGIN_ATTEMPT | attempt_id=%s | username=%s | result=FAILED | "
            "reason=user_not_found | ip=%s | user_agent=%s",
            attempt_id, username, client_ip, user_agent
        )
        return jsonify({'error': 'Invalid username or password'}), 401

    # Verify password
    if not check_password_hash(user['password_hash'], password):
        record_failed_attempt(client_ip)
        record_failed_attempt(username)

        attempts_remaining = MAX_ATTEMPTS - login_attempts.get(username, (0, None))[0]

        logger.warning(
            "LOGIN_ATTEMPT | attempt_id=%s | username=%s | email=%s | "
            "result=FAILED | reason=invalid_password | "
            "attempts_remaining=%d | ip=%s | user_agent=%s",
            attempt_id, username, user['email'], attempts_remaining,
            client_ip, user_agent
        )
        return jsonify({'error': 'Invalid username or password'}), 401

    # Successful login
    clear_failed_attempts(client_ip)
    clear_failed_attempts(username)

    logger.info(
        "LOGIN_ATTEMPT | attempt_id=%s | username=%s | email=%s | "
        "result=SUCCESS | ip=%s | user_agent=%s",
        attempt_id, username, user['email'], client_ip, user_agent
    )

    return jsonify({
        'message': 'Login successful',
        'user': {
            'username': username,
            'email': user['email']
        }
    }), 200


